import 'package:flutter/material.dart';

void main() => runApp(const MaterialApp(home: HomePage()));

// STATELESS ã its output is purely a function of the constructor args.
class Greeting extends StatelessWidget {
  const Greeting({super.key, required this.name});
  final String name;

  @override
  Widget build(BuildContext context) {
    return Text(
      'Hello, $name!',
      style: Theme.of(context).textTheme.headlineMedium,
    );
  }
}

// STATEFUL ã has internal `_count` state that survives rebuilds.
class Counter extends StatefulWidget {
  const Counter({super.key});

  @override
  State<Counter> createState() => _CounterState();
}

class _CounterState extends State<Counter> {
  int _count = 0;

  void _increment() {
    setState(() => _count++);   // schedule a rebuild
  }

  @override
  Widget build(BuildContext context) {
    return Column(
      mainAxisSize: MainAxisSize.min,
      children: [
        Text('count = $_count', style: const TextStyle(fontSize: 32)),
        const SizedBox(height: 8),
        FilledButton(onPressed: _increment, child: const Text('+1')),
      ],
    );
  }
}

class HomePage extends StatelessWidget {
  const HomePage({super.key});

  @override
  Widget build(BuildContext context) => Scaffold(
    appBar: AppBar(title: const Text('Widgets demo')),
    body: const Center(
      child: Column(
        mainAxisAlignment: MainAxisAlignment.center,
        children: [
          Greeting(name: 'Ada'),      // stateless ã rebuilds only if name changes
          SizedBox(height: 32),
          Counter(),                   // stateful ã its own _count survives rebuilds
        ],
      ),
    ),
  );
}
